solution.approach:
For each test case we apply the classic Bubble Sort algorithm. We repeatedly scan the array, swapping adjacent elements that are out of order. After the i‑th pass the largest i elements are guaranteed to be at the end, so the inner loop can stop at N‑i‑1. The algorithm is simple, works in‑place and meets the problem requirements.

Pseudo‑code:
for each test case:
    read N and array A
    for i from 0 to N-2:
        for j from 0 to N-i-2:
            if A[j] > A[j+1]: swap A[j] and A[j+1]
    output A

code.C:
#include <stdio.h>

void bubbleSort(int arr[], int n) {
    for (int i = 0; i < n - 1; ++i) {
        for (int j = 0; j < n - i - 1; ++j) {
            if (arr[j] > arr[j + 1]) {
                int tmp = arr[j];
                arr[j] = arr[j + 1];
                arr[j + 1] = tmp;
            }
        }
    }
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int arr[1000];
        for (int i = 0; i < N; ++i) scanf("%d", &arr[i]);
        bubbleSort(arr, N);
        for (int i = 0; i < N; ++i) {
            printf("%d", arr[i]);
            if (i + 1 < N) printf(" ");
        }
        printf("\n");
    }
    return 0;
}

