import java.util.*;

public class Main {
    static void bubbleSort(int[] arr) {
        int n = arr.length;
        for (int i = 0; i < n - 1; ++i) {
            for (int j = 0; j < n - i - 1; ++j) {
                if (arr[j] > arr[j + 1]) {
                    int tmp = arr[j];
                    arr[j] = arr[j + 1];
                    arr[j + 1] = tmp;
                }
            }
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] arr = new int[N];
            for (int i = 0; i < N; ++i) arr[i] = sc.nextInt();
            bubbleSort(arr);
            for (int i = 0; i < N; ++i) {
                System.out.print(arr[i]);
                if (i + 1 < N) System.out.print(' ');
            }
            System.out.println();
        }
        sc.close();
    }
}

